// Expect shim for user-written test assertions
function expect(val) {
  return {
    toBe(expected) { if (val !== expected) throw new Error("Expected " + expected + ", got " + val); },
    toBeTruthy() { if (!val) throw new Error("Expected truthy, got " + val); },
    toHaveProperty(key) { if (!(key in (val || {}))) throw new Error("Expected property " + key); },
    toBeGreaterThan(n) { if (!(val > n)) throw new Error("Expected > " + n + ", got " + val); }
  };
}

function _expectStatus(response, expected) {
  const actual = response.status;
  if (actual === expected) return;
  const where = _lastCall && _lastCall.line ? " [clear:" + _lastCall.line + "]" : "";
  const call = _lastCall && _lastCall.method ? _lastCall.method + " " + _lastCall.path : "the request";
  const bodyHint = _responseBody && _responseBody.error ? " Server said: \"" + String(_responseBody.error).slice(0, 120) + "\"." : "";
  // Translate each status code into plain English. The hint names the problem
  // AND points at the Clear code that needs to change.
  let why = "";
  if (actual === 404) {
    why = "404 means \"there is no endpoint at that URL.\" Either the path in your test is wrong, or you forgot to write `when user calls " + _lastCall.method + " " + _lastCall.path + ":` in your Clear file.";
  } else if (actual === 401) {
    why = "401 means \"you have to be logged in to do this.\" The endpoint has `requires login` but the test didn't send an auth token.";
  } else if (actual === 403) {
    why = "403 means \"you're logged in but not allowed to do this.\" The endpoint has `requires role 'admin'` (or similar) and the test user doesn't have that role.";
  } else if (actual === 400) {
    why = "400 means \"the server didn't like the data you sent.\" Usually a `validate` rule rejected it — a required field is missing, empty, or the wrong type.";
  } else if (actual === 409) {
    why = "409 means \"something already exists with that value.\" A field marked `unique` (like email) already has a record with that value — use a different value or delete the old record first.";
  } else if (actual === 422) {
    why = "422 means \"the data was the right shape but failed a rule.\" A `validate` block rejected it (wrong format, out of range, etc).";
  } else if (actual === 429) {
    why = "429 means \"too many requests.\" A `rate limit` rule is throttling the test. Wait, or raise the limit in your Clear code.";
  } else if (actual >= 500 && actual < 600) {
    why = "5xx means \"the server crashed trying to handle this.\" Check the app logs for a stack trace — usually an unhandled error in the endpoint body.";
  } else if (expected === 201 && actual === 200) {
    why = "200 means \"success\" and 201 means \"success, and I created a new record.\" Your endpoint returned success but not the 'created' flavor. Add `with status 201` to the `send back` line after a save.";
  } else if (expected === 200 && actual === 201) {
    why = "201 means \"created\" and 200 means \"success.\" The test expected a plain success but got a created — change the test to expect 201, or change the endpoint to `send back X` without `with status 201`.";
  } else if (expected === 204 && actual === 200) {
    why = "204 means \"done, nothing to send back\" (used for deletes). The endpoint returned 200 with a body. Either change the test to 200, or drop the value from `send back` and add `with status 204`.";
  } else if (actual === 200 && expected === 200) {
    why = "This shouldn't happen — statuses match.";
  } else if (actual === 201 && expected === 201) {
    why = "This shouldn't happen — statuses match.";
  } else if (actual >= 200 && actual < 300 && expected >= 400) {
    why = "The test expected this to fail, but the server accepted it with " + actual + " (success). Either the validation rule you want is missing, or the test data is actually valid.";
  } else {
    why = "The server returned " + actual + " but the test expected " + expected + ". Statuses in the 2xx range mean success, 4xx means the request had a problem, 5xx means the server had a problem.";
  }
  throw new Error(call + " returned " + actual + " (expected " + expected + "). " + why + bodyHint + where);
}

function _expectBodyHas(body, key) {
  if (body && typeof body === "object" && key in body) return;
  const where = _lastCall && _lastCall.line ? " [clear:" + _lastCall.line + "]" : "";
  const call = _lastCall && _lastCall.method ? _lastCall.method + " " + _lastCall.path : "the endpoint";
  const got = body === null || body === undefined ? "nothing" : "{ " + Object.keys(body).slice(0, 5).join(", ") + " }";
  throw new Error(call + " didn't return a \"" + key + "\" field — got " + got + ". Your endpoint's `send back` line needs to include \"" + key + "\"." + where);
}

function _expectSuccess(response) {
  if (response.status >= 200 && response.status < 300) return;
  const where = _lastCall && _lastCall.line ? " [clear:" + _lastCall.line + "]" : "";
  const call = _lastCall && _lastCall.method ? _lastCall.method + " " + _lastCall.path : "the request";
  throw new Error(call + " returned " + response.status + " but the test expected any 2xx success." + where);
}

function _expectFailure(response) {
  if (response.status >= 400) return;
  const where = _lastCall && _lastCall.line ? " [clear:" + _lastCall.line + "]" : "";
  const call = _lastCall && _lastCall.method ? _lastCall.method + " " + _lastCall.path : "the request";
  throw new Error(call + " returned " + response.status + " (success) but the test expected it to fail with a 4xx or 5xx. Add a `validate` or `requires login` rule to the endpoint, or change the test data so the validation actually rejects it." + where);
}

function _expectBodyContains(body, value) {
  const as = JSON.stringify(body);
  if (as && as.includes(value)) return;
  const where = _lastCall && _lastCall.line ? " [clear:" + _lastCall.line + "]" : "";
  const call = _lastCall && _lastCall.method ? _lastCall.method + " " + _lastCall.path : "the endpoint";
  throw new Error(call + " response didn't contain \"" + value + "\". Got: " + (as || "nothing") + "." + where);
}

function _expectBodyLength(body, min) {
  const len = Array.isArray(body) ? body.length : (body && typeof body === "object" ? Object.keys(body).length : 0);
  if (len > min) return;
  const where = _lastCall && _lastCall.line ? " [clear:" + _lastCall.line + "]" : "";
  const call = _lastCall && _lastCall.method ? _lastCall.method + " " + _lastCall.path : "the endpoint";
  throw new Error(call + " returned " + len + " item(s) but the test expected more than " + min + ". Either the endpoint isn't reading from the table you think, or the test data hasn't been created yet." + where);
}

function _expectBodyTruthy(body) {
  if (body) return;
  const where = _lastCall && _lastCall.line ? " [clear:" + _lastCall.line + "]" : "";
  const call = _lastCall && _lastCall.method ? _lastCall.method + " " + _lastCall.path : "the endpoint";
  throw new Error(call + " returned an empty body. Your endpoint should `send back` something." + where);
}

function _expectErrorContains(body, value) {
  const as = JSON.stringify(body);
  if (as && as.includes(value)) return;
  const where = _lastCall && _lastCall.line ? " [clear:" + _lastCall.line + "]" : "";
  throw new Error("Error response didn't mention \"" + value + "\". Got: " + (as || "nothing") + ". Check the `fail with error '...'` or `validate` message in your endpoint." + where);
}

